import { api } from "@/lib/api/axios";
import { TotalStats } from "../types/dashboard.types";
import { DASHBOARD_TOTAL_STATS_ROUTES } from "../routes/dashboard-total-stats.routes";
import { DASHBOARD_MONTHLY_STATS_ROUTES } from "../routes/dashboard-monthly-stats.routes";


export const getDepartmentsTotalStats = () => {
    return api.get<TotalStats>(DASHBOARD_TOTAL_STATS_ROUTES.getDepartmentsTotalStats);
}

export const getJobsTotalStats = () => {
    return api.get<TotalStats>(DASHBOARD_TOTAL_STATS_ROUTES.getJobsTotalStats);
}

export const getApplicationsTotalStats = () => {
    return api.get<TotalStats>(DASHBOARD_TOTAL_STATS_ROUTES.getApplicationsTotalStats);
}

export const getDepartmentsMonthlyStats = () => {
    return api.get(DASHBOARD_MONTHLY_STATS_ROUTES.getDepartmentsMonthlyStats);
}

export const getJobsMonthlyStats = () => {
    return api.get(DASHBOARD_MONTHLY_STATS_ROUTES.getJobsMonthlyStats);
}

export const getApplicationsMonthlyStats = () => {
    return api.get(DASHBOARD_MONTHLY_STATS_ROUTES.getApplicationsMonthlyStats);
}
